import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Divider } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface Deck {
  name: string;
  cardsDue: number;
  accuracyRate: number;
  masteryLevel: string;
}

interface WidgetData {
  decks: Deck[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const { decks } = widgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFF8E1' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" color="primary" sx={{ fontWeight: 600 }}>
            Flashcard Review
          </Typography>
          {decks.map((deck, index) => (
            <Box key={index}>
              <Typography variant="body1" sx={{ fontWeight: 500 }}>
                {deck.name}
              </Typography>
              <Stack direction="row" spacing={1} alignItems="center" sx={{ my: 0.5 }}>
                <Typography variant="body2" color="text.secondary">
                  Cards Due: {deck.cardsDue}
                </Typography>
                <Divider orientation="vertical" flexItem />
                <Typography variant="body2" color="text.secondary">
                  Accuracy: {deck.accuracyRate}%
                </Typography>
                <Divider orientation="vertical" flexItem />
                <Chip
                  label={deck.masteryLevel}
                  sx={{ backgroundColor: '#ECEFF1', fontSize: '11px' }}
                />
              </Stack>
              <Divider sx={{ my: 1 }} />
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
